import { readFileSync } from "fs";

/**
 * Creates an Eleventy data function that reads the asset manifest
 * generated by the wtfm-manifest Rollup plugin.
 *
 * @param {object} options
 * @param {string} options.manifestPath - Absolute path to asset-manifest.json
 * @returns {function} Eleventy data function
 */
export default function createManifestData(options = {}) {
  const { manifestPath } = options;

  return () => {
    try {
      return JSON.parse(readFileSync(manifestPath, "utf-8"));
    } catch {
      return {};
    }
  };
}
